{
  "name": "DisasterAI: Emergency Management Platform",
  "description": "An AI-powered dashboard for real-time disaster monitoring, risk assessment, and response coordination. It leverages generative AI to analyze incoming reports, generate action plans, and provide multilingual alerts."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import Header from './components/Header';
import StatCards from './components/StatCards';
import NavTabs from './components/NavTabs';
import AlertsSection from './components/AlertsSection';
import NewAlertModal from './components/NewAlertModal';
import { initialAlerts, statCardData } from './constants';
import { Alert, Tab } from './types';

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>('Alerts');
  const [alerts, setAlerts] = useState<Alert[]>(initialAlerts);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleNewAlert = (newAlert: Alert) => {
    setAlerts(prevAlerts => [newAlert, ...prevAlerts]);
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans text-slate-800">
      <Header />
      <main className="p-4 sm:p-6 lg:p-8">
        <StatCards stats={statCardData} />
        <NavTabs activeTab={activeTab} setActiveTab={setActiveTab} />

        {activeTab === 'Alerts' && (
          <AlertsSection alerts={alerts} onNewAlertClick={() => setIsModalOpen(true)} />
        )}
        {activeTab === 'Live Map' && (
          <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
            <h2 className="text-xl font-bold mb-4">Live Disaster Map</h2>
            <p className="text-slate-600">Map integration would be displayed here, showing real-time locations of active alerts and resource units.</p>
            <div className="mt-4 h-96 bg-slate-200 rounded-md flex items-center justify-center">
                <p className="text-slate-500">Leaflet.js or Google Maps API component placeholder</p>
            </div>
          </div>
        )}
        {['Assessment', 'Resources', 'Emergency'].includes(activeTab) && (
            <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
                <h2 className="text-xl font-bold mb-4">{activeTab}</h2>
                <p className="text-slate-600">This is a placeholder for the {activeTab} section. Functionality would be built out here.</p>
            </div>
        )}
      </main>
      {isModalOpen && <NewAlertModal onClose={() => setIsModalOpen(false)} onAddAlert={handleNewAlert} />}
    </div>
  );
}

export enum AlertSeverity {
    LOW = 'Low',
    MEDIUM = 'Medium',
    HIGH = 'High',
    CRITICAL = 'Critical',
}

export enum AlertStatus {
    ACTIVE = 'Active',
    MONITORING = 'Monitoring',
    RESOLVED = 'Resolved',
    UPDATING = 'Updating',
}

export interface Alert {
    id: string;
    title: string;
    type: string;
    description: string;
    location: string;
    affected: number;
    timestamp: Date;
    severity: AlertSeverity;
    status: AlertStatus;
}

export type Tab = 'Alerts' | 'Live Map' | 'Assessment' | 'Resources' | 'Emergency';

import { GoogleGenAI, Type } from "@google/genai";
import { AlertSeverity } from "../types";

// IMPORTANT: This service assumes the API_KEY is set in the environment.
// In a real application, this key should be handled securely and not exposed on the client-side.
// This code is for demonstration purposes.
const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  console.warn("Gemini API key not found. Please set the API_KEY environment variable.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

export const assessRiskAndCategorize = async (report: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze the following disaster report and provide a structured JSON response.
        Report: "${report}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "A concise title for the alert (e.g., 'Structural Collapse Downtown')." },
            summary: { type: Type.STRING, description: "A brief, one-sentence summary of the event." },
            disasterType: { type: Type.STRING, description: "Categorize the disaster type (e.g., 'Earthquake', 'Flood', 'Fire', 'Industrial Accident')." },
            severity: {
              type: Type.STRING,
              description: "Assess the severity. Must be one of: 'Low', 'Medium', 'High', 'Critical'.",
            },
          },
          required: ["title", "summary", "disasterType", "severity"],
        },
      },
    });

    const parsed = JSON.parse(response.text);
    // Ensure severity aligns with our enum
    const severityValues = Object.values(AlertSeverity) as string[];
    if (!severityValues.includes(parsed.severity)) {
        throw new Error(`Invalid severity returned: ${parsed.severity}`);
    }

    return parsed as { title: string; summary: string, disasterType: string, severity: AlertSeverity };
  } catch (error) {
    console.error("Error assessing risk:", error);
    throw new Error("Failed to analyze the disaster report with AI.");
  }
};

export const generateActionPlan = async (disasterType: string, severity: AlertSeverity) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a concise, step-by-step emergency action plan for a '${disasterType}' of '${severity}' severity. The plan should be a numbered list of 3-5 key actions for first responders.`,
    });
    return response.text;
  } catch (error) {
    console.error("Error generating action plan:", error);
    throw new Error("Failed to generate an action plan.");
  }
};

export const translateAlert = async (text: string, languages: string[]) => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Translate the following alert into these languages: ${languages.join(', ')}. Return a JSON object where keys are the language names and values are the translations.
            Alert: "${text}"`,
            config: {
                responseMimeType: "application/json",
            },
        });
        return JSON.parse(response.text) as Record<string, string>;
    } catch (error) {
        console.error("Error translating alert:", error);
        throw new Error("Failed to translate the alert.");
    }
};

import React from 'react';
import { TriangleAlert, Users, LineChart, Zap } from 'lucide-react';

const icons = {
  TriangleAlert: <TriangleAlert className="h-6 w-6 text-slate-400" />,
  Users: <Users className="h-6 w-6 text-slate-400" />,
  LineChart: <LineChart className="h-6 w-6 text-slate-400" />,
  Zap: <Zap className="h-6 w-6 text-slate-400" />,
};

interface StatCardProps {
  title: string;
  value: string;
  change: string;
  icon: keyof typeof icons;
}

const StatCard: React.FC<StatCardProps> = ({ title, value, change, icon }) => {
  return (
    <div className="bg-white p-5 rounded-lg shadow-sm relative overflow-hidden">
        <div className="flex justify-between items-start">
            <div>
                <p className="text-sm text-slate-500">{title}</p>
                <p className="text-3xl font-bold text-slate-800 mt-1">{value}</p>
                <p className="text-xs text-slate-500 mt-2">{change}</p>
            </div>
            {icons[icon]}
        </div>
        <div className="absolute bottom-0 left-0 h-1 w-full bg-gradient-to-r from-orange-400 to-red-400"></div>
    </div>
  );
};

interface StatCardsProps {
    stats: StatCardProps[];
}

const StatCards: React.FC<StatCardsProps> = ({ stats }) => {
    return (
        <section>
            <div className="flex items-center gap-2 mb-4">
                <LineChart className="h-5 w-5" />
                <h2 className="text-xl font-bold">Emergency Status Overview</h2>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {stats.map((stat, index) => (
                    <StatCard key={index} {...stat} />
                ))}
