import React from 'react';
import { TriangleAlert, ChevronRight, MapPin, Users, Clock } from 'lucide-react';
import { Alert, AlertSeverity, AlertStatus } from '../types';

const severityConfig = {
    [AlertSeverity.CRITICAL]: {
        bgColor: 'bg-red-50',
        borderColor: 'border-red-500',
        textColor: 'text-red-700',
        iconColor: 'text-red-500',
        tagColor: 'bg-red-500 text-white',
    },
    [AlertSeverity.HIGH]: {
        bgColor: 'bg-orange-50',
        borderColor: 'border-orange-500',
        textColor: 'text-orange-700',
        iconColor: 'text-orange-500',
        tagColor: 'bg-orange-500 text-white',
    },
    [AlertSeverity.MEDIUM]: {
        bgColor: 'bg-yellow-50',
        borderColor: 'border-yellow-500',
        textColor: 'text-yellow-700',
        iconColor: 'text-yellow-500',
        tagColor: 'bg-yellow-500 text-white',
    },
    [AlertSeverity.LOW]: {
        bgColor: 'bg-blue-50',
        borderColor: 'border-blue-500',
        textColor: 'text-blue-700',
        iconColor: 'text-blue-500',
        tagColor: 'bg-blue-500 text-white',
    },
};

const statusColors = {
    [AlertStatus.ACTIVE]: 'bg-red-500 text-white',
    [AlertStatus.MONITORING]: 'bg-yellow-500 text-white',
    [AlertStatus.RESOLVED]: 'bg-green-500 text-white',
    [AlertStatus.UPDATING]: 'bg-blue-500 text-white',
};

function timeSince(date: Date) {
    const seconds = Math.floor((new Date().getTime() - date.getTime()) / 1000);
    let interval = seconds / 31536000;
    if (interval > 1) return Math.floor(interval) + " years ago";
    interval = seconds / 2592000;
    if (interval > 1) return Math.floor(interval) + " months ago";
    interval = seconds / 86400;
    if (interval > 1) return Math.floor(interval) + " days ago";
    interval = seconds / 3600;
    if (interval > 1) return Math.floor(interval) + " hours ago";
    interval = seconds / 60;
    if (interval > 1) return Math.floor(interval) + " minutes ago";
    return Math.floor(seconds) + " seconds ago";
}

const AlertCard: React.FC<{ alert: Alert }> = ({ alert }) => {
    const config = severityConfig[alert.severity] || severityConfig[AlertSeverity.MEDIUM];

    return (
        <div className={`border ${config.borderColor} ${config.bgColor} p-4 rounded-lg shadow-sm`}>
            <div className="flex justify-between items-start">
                <div className="flex items-start gap-3">
                    <TriangleAlert className={`h-6 w-6 ${config.iconColor} mt-1`} />
                    <div>
                        <div className="flex items-center gap-3">
                            <h3 className={`text-lg font-bold ${config.textColor}`}>{alert.title}</h3>
                            <span className="text-xs font-semibold bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{alert.type}</span>
                            <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${statusColors[alert.status]}`}>{alert.status.toUpperCase()}</span>
                        </div>
                        <p className="text-sm text-slate-600 mt-1">{alert.description}</p>
                    </div>
                </div>
                <ChevronRight className="h-5 w-5 text-slate-400" />
            </div>

            <div className="mt-4 pt-4 border-t border-red-200 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div className="flex flex-wrap items-center gap-x-6 gap-y-2 text-sm text-slate-500">
                    <div className="flex items-center gap-1.5"><MapPin className="h-4 w-4" /> {alert.location}</div>
                    <div className={`flex items-center gap-1.5 ${config.textColor}`}><Users className="h-4 w-4" /> {alert.affected.toLocaleString()} affected</div>
                    <div className="flex items-center gap-1.5"><Clock className="h-4 w-4" /> {timeSince(alert.timestamp)}</div>
                </div>
                <div className="flex items-center gap-2 mt-2 sm:mt-0">
                    <button className="bg-gradient-to-r from-orange-500 to-red-500 text-white rounded-md px-4 py-1.5 text-sm font-medium hover:opacity-90 shadow-sm">Respond</button>
                    <button className="bg-white border border-slate-300 rounded-md px-4 py-1.5 text-sm font-medium hover:bg-slate-50">View Details</button>
                    <button className="bg-white border border-slate-300 rounded-md px-4 py-1.5 text-sm font-medium hover:bg-slate-50">Update Status</button>
                </div>
            </div>
        </div>
    );
};

export default AlertCard;

import React, { useState } from 'react';
import { Alert, AlertSeverity, AlertStatus } from '../types';
import { assessRiskAndCategorize, generateActionPlan, translateAlert } from '../services/geminiService';
import { X, Bot, FileText, Languages } from 'lucide-react';

interface NewAlertModalProps {
  onClose: () => void;
  onAddAlert: (alert: Alert) => void;
}

const NewAlertModal: React.FC<NewAlertModalProps> = ({ onClose, onAddAlert }) => {
  const [report, setReport] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [assessedData, setAssessedData] = useState<{ title: string; summary: string, disasterType: string, severity: AlertSeverity } | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [translations, setTranslations] = useState<Record<string, string> | null>(null);

  const handleAssessRisk = async () => {
    if (!report) return;
    setIsLoading(true);
    setError(null);
    setAssessedData(null);
    setActionPlan(null);
    setTranslations(null);
    try {
      const result = await assessRiskAndCategorize(report);
      setAssessedData(result);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleGeneratePlan = async () => {
    if (!assessedData) return;
    setIsLoading(true);
    setError(null);
    try {
        const plan = await generateActionPlan(assessedData.disasterType, assessedData.severity);
        setActionPlan(plan);
    } catch (e) {
        setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
        setIsLoading(false);
    }
  };

  const handleTranslate = async () => {
    if (!assessedData) return;
    setIsLoading(true);
    setError(null);
    try {
        const languages = ['Spanish', 'French', 'Mandarin'];
        const result = await translateAlert(assessedData.summary, languages);
        setTranslations(result);
    } catch(e) {
        setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
        setIsLoading(false);
    }
  }

  const handleSubmitAlert = () => {
    if (!assessedData) return;
    const newAlert: Alert = {
      id: `alert-${Date.now()}`,
      title: assessedData.title,
      type: assessedData.disasterType,
      description: assessedData.summary,
      location: 'Unspecified', // This would come from the form in a real app
      affected: 0, // This would also come from the form
      timestamp: new Date(),
      severity: assessedData.severity,
      status: AlertStatus.ACTIVE,
    };
    onAddAlert(newAlert);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col">
        <div className="p-4 border-b flex justify-between items-center">
          <h2 className="text-lg font-bold">Create New Emergency Alert</h2>
          <button onClick={onClose} className="text-slate-500 hover:text-slate-800"><X /></button>
        </div>

        <div className="p-6 overflow-y-auto space-y-6">
          <div>
            <label htmlFor="report" className="block text-sm font-medium text-slate-700 mb-1">Incoming Disaster Report</label>
            <textarea
              id="report"
              rows={4}
              value={report}
              onChange={(e) => setReport(e.target.value)}
              placeholder="Paste or type the report here. e.g., 'Seismic activity detected in Zone 4. Reports of building collapses near city center.'"
              className="w-full border-slate-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500"
            />
          </div>

          <button
            onClick={handleAssessRisk}
            disabled={!report || isLoading}
            className="w-full flex justify-center items-center gap-2 bg-slate-700 text-white rounded-md px-4 py-2 font-semibold hover:bg-slate-800 disabled:bg-slate-400"
          >
            <Bot className="h-5 w-5" />
            {isLoading && !assessedData ? 'Assessing...' : 'Use AI to Assess Risk & Categorize'}
          </button>

          {error && <div className="text-red-600 bg-red-50 p-3 rounded-md text-sm">{error}</div>}

          {assessedData && (
            <div className="bg-slate-50 p-4 rounded-md border space-y-4">
              <h3 className="font-bold text-slate-800">AI Assessment Complete</h3>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div><strong className="block text-slate-500">Title:</strong> {assessedData.title}</div>
                <div><strong className="block text-slate-500">Disaster Type:</strong> {assessedData.disasterType}</div>
                <div><strong className="block text-slate-500">Severity:</strong> <span className="font-bold text-red-600">{assessedData.severity}</span></div>
              </div>
              <div><strong className="block text-slate-500">Summary:</strong> {assessedData.summary}</div>

              <div className="flex gap-2 pt-4 border-t">
                <button onClick={handleGeneratePlan} disabled={isLoading} className="flex-1 text-sm flex items-center justify-center gap-2 bg-blue-600 text-white px-3 py-2 rounded-md hover:bg-blue-700 disabled:bg-blue-300"><FileText size={16}/>Generate Action Plan</button>
                <button onClick={handleTranslate} disabled={isLoading} className="flex-1 text-sm flex items-center justify-center gap-2 bg-green-600 text-white px-3 py-2 rounded-md hover:bg-green-700 disabled:bg-green-300"><Languages size={16}/>Translate Alert</button>
              </div>

              {actionPlan && <div className="pt-4 border-t"><h4 className="font-semibold mb-2">Generated Action Plan:</h4><pre className="text-sm bg-white p-3 rounded whitespace-pre-wrap font-sans">{actionPlan}</pre></div>}
              {translations && <div className="pt-4 border-t"><h4 className="font-semibold mb-2">Translations:</h4><ul className="text-sm bg-white p-3 rounded space-y-1">{Object.entries(translations).map(([lang, text]) => <li key={lang}><strong>{lang}:</strong> {text}</li>)}</ul></div>}
            </div>
          )}

        </div>

        <div className="p-4 border-t bg-slate-50 flex justify-end gap-3">
          <button onClick={onClose} className="bg-white border border-slate-300 rounded-md px-4 py-2 text-sm font-medium hover:bg-slate-50">Cancel</button>
          <button 
            onClick={handleSubmitAlert}
            disabled={!assessedData}
            className="bg-gradient-to-r from-orange-500 to-red-500 text-white rounded-md px-4 py-2 text-sm font-medium hover:opacity-90 shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Create Alert
          </button>
        </div>
      </div>
    </div>
  );
};

export default NewAlertModal;

