interface NewAlertModalProps {
  onClose: () => void;
  onAddAlert: (alert: Alert) => void;
}

const NewAlertModal: React.FC<NewAlertModalProps> = ({ onClose, onAddAlert }) => {
  const [report, setReport] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [assessedData, setAssessedData] = useState<{ title: string; summary: string, disasterType: string, severity: AlertSeverity } | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [translations, setTranslations] = useState<Record<string, string> | null>(null);

  const handleAssessRisk = async () => {
    if (!report) return;
    setIsLoading(true);
    setError(null);
    setAssessedData(null);
    setActionPlan(null);
    setTranslations(null);
    try {
      const result = await assessRiskAndCategorize(report);
      setAssessedData(result);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleGeneratePlan = async () => {
    if (!assessedData) return;
    setIsLoading(true);
    setError(null);
    try {
        const plan = await generateActionPlan(assessedData.disasterType, assessedData.severity);
        setActionPlan(plan);
    } catch (e) {
        setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
        setIsLoading(false);
    }
  };

  const handleTranslate = async () => {
    if (!assessedData) return;
    setIsLoading(true);
    setError(null);
    try {
        const languages = ['Spanish', 'French', 'Mandarin'];
        const result = await translateAlert(assessedData.summary, languages);
        setTranslations(result);
    } catch(e) {
        setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
        setIsLoading(false);
    }
  }

  const handleSubmitAlert = () => {
    if (!assessedData) return;
    const newAlert: Alert = {
      id: `alert-${Date.now()}`,
      title: assessedData.title,
      type: assessedData.disasterType,
      description: assessedData.summary,
      location: 'Unspecified', // This would come from the form in a real app
      // Randomize around India
      lat: 20.5937 + (Math.random() - 0.5) * 20, 
      lng: 78.9629 + (Math.random() - 0.5) * 20,
      affected: 0, // This would also come from the form
      timestamp: new Date(),
      severity: assessedData.severity,
      status: AlertStatus.ACTIVE,
    };
    onAddAlert(newAlert);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col">
