        </div>

        <div className="p-6 overflow-y-auto space-y-6">
          <div>
            <label htmlFor="report" className="block text-sm font-medium text-slate-700 mb-1">Incoming Disaster Report</label>
            <textarea
              id="report"
              rows={4}
              value={report}
              onChange={(e) => setReport(e.target.value)}
              placeholder="Paste or type the report here. e.g., 'Seismic activity detected in Zone 4. Reports of building collapses near city center.'"
              className="w-full border-slate-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500"
            />
          </div>

          <button
