import React, { useEffect, useRef } from 'react';
import { Alert, AlertSeverity } from '../types';
import { timeSince } from '../utils';

declare const L: any; // Use Leaflet from global scope

interface LiveMapProps {
  alerts: Alert[];
}

const severityColors = {
    [AlertSeverity.CRITICAL]: '#ef4444', // red-500
    [AlertSeverity.HIGH]: '#f97316', // orange-500
    [AlertSeverity.MEDIUM]: '#eab308', // yellow-500
    [AlertSeverity.LOW]: '#3b82f6', // blue-500
};

const customIcon = (color: string) => L.divIcon({
    html: `<svg viewBox="0 0 24 24" width="32" height="32" fill="${color}" xmlns="http://www.w3.org/2000/svg"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/><circle cx="12" cy="9.5" r="2.5" fill="white"/></svg>`,
    className: '', // important to have empty className
    iconSize: [32, 32],
    iconAnchor: [16, 32],
    popupAnchor: [0, -32]
});


const LiveMap: React.FC<LiveMapProps> = ({ alerts }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<any>(null);
    const markersRef = useRef<any[]>([]);

    useEffect(() => {
        if (mapContainerRef.current && !mapRef.current) {
            const map = L.map(mapContainerRef.current).setView([20.5937, 78.9629], 5);
            mapRef.current = map;

            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
            }).addTo(map);
        }
    }, []); 

    useEffect(() => {
        if (mapRef.current) {
            const map = mapRef.current;
            markersRef.current.forEach(marker => map.removeLayer(marker));
            markersRef.current = [];

            alerts.forEach(alert => {
                const color = severityColors[alert.severity] || 'gray';
                const buttonId = `respond-btn-${alert.id}`;
                const marker = L.marker([alert.lat, alert.lng], { icon: customIcon(color) }).addTo(map);
                marker.bindPopup(`
                    <div style="font-family: sans-serif; font-size: 14px; max-width: 250px; line-height: 1.5;">
                        <b style="font-size: 16px; color: #1e293b;">${alert.title}</b>
                        <p style="font-size: 13px; color: #475569; margin: 4px 0;">${alert.description}</p>
                        <hr style="border: 0; border-top: 1px solid #e2e8f0; margin: 8px 0;" />
                        <div style="display: grid; grid-template-columns: 80px 1fr; gap: 4px; color: #334155;">
                            <b>Severity:</b> <span>${alert.severity}</span>
                            <b>Location:</b> <span>${alert.location}</span>
                            <b>Affected:</b> <span>${alert.affected.toLocaleString()}</span>
                            <b>Time:</b> <span>${timeSince(alert.timestamp)}</span>
                        </div>
                        <button id="${buttonId}" style="width: 100%; margin-top: 12px; padding: 8px 12px; border: none; background: linear-gradient(to right, #f97316, #ef4444); color: white; border-radius: 6px; font-weight: 600; cursor: pointer;">Respond</button>
                    </div>
                `);

                marker.on('popupopen', () => {
                    const btn = document.getElementById(buttonId);
                    if (btn) {
                        btn.onclick = () => alert(`Responding to alert: ${alert.title}`);
                    }
                });

                markersRef.current.push(marker);
            });
        }
    }, [alerts]);

    return (
      <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
        <h2 className="text-xl font-bold mb-4">Live Disaster Map</h2>
        <p className="text-slate-600 mb-4">Showing real-time locations of active alerts.</p>
        <div ref={mapContainerRef} id="map" className="h-[500px] w-full rounded-md z-0" />
      </div>
    );
};

export default LiveMap;

import React, { useState } from 'react';
import { Alert } from '../types';
import { generateDetailedAssessment } from '../services/geminiService';
import { BrainCircuit, Bot } from 'lucide-react';

interface AssessmentSectionProps {
    alerts: Alert[];
}

const AssessmentSection: React.FC<AssessmentSectionProps> = ({ alerts }) => {
    const [selectedAlertId, setSelectedAlertId] = useState<string>('');
    const [isLoading, setIsLoading] = useState(false);
    const [assessment, setAssessment] = useState<string>('');
    const [error, setError] = useState<string>('');

    const handleGenerate = async () => {
        if (!selectedAlertId) {
            setError('Please select an alert to assess.');
            return;
        }
        const selectedAlert = alerts.find(a => a.id === selectedAlertId);
        if (!selectedAlert) {
            setError('Could not find the selected alert.');
            return;
        }

        setIsLoading(true);
        setError('');
        setAssessment('');

        try {
            const result = await generateDetailedAssessment(selectedAlert);
            setAssessment(result);
        } catch (e) {
            setError(e instanceof Error ? e.message : 'An unknown error occurred.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
            <div className="flex justify-between items-start">
                <div>
                    <h2 className="text-2xl font-bold">AI-Powered Risk Assessment</h2>
                    <p className="text-slate-500 mt-1">Generate intelligent disaster risk analysis and recommendations</p>
                </div>
                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => alert('Opening AI Assistant chat...')}
                        className="flex items-center gap-2 bg-white border border-slate-300 rounded-lg px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 shadow-sm"
                        style={{ background: 'linear-gradient(to right, #f3e8ff, #e9d5ff)', color: '#8b5cf6' }}
                    >
                        <BrainCircuit size={16} />
                        AI Assistant
                    </button>
                </div>
            </div>

            <div className="mt-6 flex items-center gap-4">
                <select
                    value={selectedAlertId}
                    onChange={(e) => setSelectedAlertId(e.target.value)}
                    className="flex-1 border-slate-300 rounded-lg shadow-sm focus:ring-purple-500 focus:border-purple-500"
                >
                    <option value="">Select an alert to assess</option>
                    {alerts.map(alert => (
                        <option key={alert.id} value={alert.id}>{alert.title}</option>
                    ))}
                </select>
                <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="flex items-center gap-2 rounded-lg px-5 py-2.5 text-sm font-semibold text-white shadow-sm transition-opacity disabled:opacity-70"
                    style={{ background: 'linear-gradient(to right, #a78bfa, #7c3aed)'}}
                >
                    <Bot size={16} />
                    {isLoading ? 'Generating...' : 'Generate Assessment'}
                </button>
            </div>

            <div className="mt-8 border-t pt-6">
                {isLoading && (
                    <div className="flex flex-col items-center justify-center text-center text-slate-500">
                        <Bot size={48} className="animate-pulse text-purple-400" />
                        <p className="mt-4 font-semibold">AI is analyzing the risk...</p>
                        <p className="text-sm">This may take a few moments.</p>
                    </div>
                )}
                {error && <p className="text-red-500 text-center">{error}</p>}

                {assessment && !isLoading && (
                    <div className="prose prose-slate max-w-none" dangerouslySetInnerHTML={{ __html: assessment.replace(/\n/g, '<br />') }} />
                )}

                {!assessment && !isLoading && !error && (
                    <div className="text-center text-slate-400">
                         <p className="font-semibold">NO ASSESSMENT GENERATED</p>
                        <p className="mt-1 text-sm">Select an alert above and click "Generate Assessment" to get AI-powered risk analysis</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AssessmentSection;

