import React, { useState } from 'react';
import { Alert, AlertSeverity, AlertStatus } from '../types';
import { assessRiskAndCategorize } from '../services/geminiService';
import { X, Bot } from 'lucide-react';

interface NewAlertModalProps {
  onClose: () => void;
  onAddAlert: (alert: Alert) => void;
}

const NewAlertModal: React.FC<NewAlertModalProps> = ({ onClose, onAddAlert }) => {
  const [report, setReport] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [assessedData, setAssessedData] = useState<{ title: string; summary: string, disasterType: string, severity: AlertSeverity } | null>(null);

  const handleAssessRisk = async () => {
    if (!report) return;
    setIsLoading(true);
    setError(null);
    setAssessedData(null);
    try {
      const result = await assessRiskAndCategorize(report);
      setAssessedData(result);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmitAlert = () => {
    if (!assessedData) {
        alert("Please assess the risk before creating an alert.");
        return;
    }
    const newAlert: Alert = {
      id: `alert-${Date.now()}`,
      title: assessedData.title,
      type: assessedData.disasterType,
      description: assessedData.summary,
      location: 'Unspecified', 
      lat: 20.5937 + (Math.random() - 0.5) * 20, 
      lng: 78.9629 + (Math.random() - 0.5) * 20,
      affected: 0,
      timestamp: new Date(),
      severity: assessedData.severity,
      status: AlertStatus.ACTIVE,
    };
    onAddAlert(newAlert);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-lg flex flex-col">
        <div className="p-5 border-b flex justify-between items-center">
          <h2 className="text-xl font-semibold text-slate-800">Create New Emergency Alert</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600"><X size={24} /></button>
        </div>

        <div className="p-6 space-y-4">
          <div>
            <label htmlFor="report" className="block text-sm font-medium text-slate-700 mb-2">Incoming Disaster Report</label>
            <textarea
              id="report"
              rows={4}
              value={report}
              onChange={(e) => setReport(e.target.value)}
              placeholder="Paste or type the report here. e.g., 'Seismic activity detected in Zone 4. Reports of building collapses near city center.'"
              className="w-full bg-slate-800 text-slate-100 placeholder-slate-400 rounded-lg p-3 focus:ring-2 focus:ring-orange-500 focus:outline-none"
            />
          </div>

          <button
            onClick={handleAssessRisk}
            disabled={!report || isLoading}
            className="w-full flex justify-center items-center gap-2 bg-slate-500 text-white rounded-lg px-4 py-2.5 font-medium hover:bg-slate-600 disabled:bg-slate-400 disabled:cursor-not-allowed transition-colors"
          >
            <Bot className="h-5 w-5" />
            {isLoading ? 'Assessing...' : 'Use AI to Assess Risk & Categorize'}
          </button>

          {error && <div className="text-red-600 text-center text-sm">{error}</div>}

          {assessedData && (
            <div className="bg-slate-50 p-4 rounded-md border text-sm">
              <h3 className="font-semibold text-slate-800 mb-2">AI Assessment Complete</h3>
              <p><strong className="text-slate-500">Title:</strong> {assessedData.title}</p>
              <p><strong className="text-slate-500">Type:</strong> {assessedData.disasterType}</p>
              <p><strong className="text-slate-500">Severity:</strong> <span className="font-bold text-red-600">{assessedData.severity}</span></p>
            </div>
          )}
        </div>

        <div className="p-5 border-t bg-slate-50 flex justify-end gap-3 rounded-b-lg">
          <button onClick={onClose} className="bg-white border border-slate-300 rounded-lg px-5 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100">Cancel</button>
          <button 
            onClick={handleSubmitAlert}
            className="bg-gradient-to-r from-orange-400 to-amber-400 text-white rounded-lg px-5 py-2 text-sm font-semibold hover:opacity-90 shadow-sm"
          >
            Create Alert
          </button>
        </div>
      </div>
    </div>
  );
};

