    setAlerts(prevAlerts => [newAlert, ...prevAlerts]);
    showNotification(`New alert "${newAlert.title}" has been successfully created.`, 'success');
  };

  const showNotification = (message: string, type: NotificationType = 'info') => {
    setNotification({ message, type });
  };

  const activeAlerts = alerts.filter(alert => alert.status === AlertStatus.ACTIVE);

  return (
    <div className="bg-slate-50 min-h-screen font-sans text-slate-800">
      <Header setNotification={showNotification} />
      <main className="p-4 sm:p-6 lg:p-8">
        <StatCards stats={statCardData} />
        <NavTabs activeTab={activeTab} setActiveTab={setActiveTab} />

        {activeTab === 'Alerts' && (
          <AlertsSection 
            alerts={alerts} 
            onNewAlertClick={() => setIsModalOpen(true)}
            onViewDetails={setViewingAlert}
            setNotification={showNotification}
          />
        )}
        {activeTab === 'Live Map' && (
          <LiveMap alerts={activeAlerts} setNotification={showNotification} />
        )}
        {activeTab === 'Assessment' && (
          <AssessmentSection alerts={alerts} setNotification={showNotification} />
        )}
        {['AI Risk Prediction', 'Emergency'].includes(activeTab) && (
            <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
                <h2 className="text-xl font-bold mb-4">{activeTab}</h2>
                <p className="text-slate-600">This is a placeholder for the {activeTab} section. Functionality would be built out here.</p>
            </div>
        )}
      </main>
      {isModalOpen && <NewAlertModal onClose={() => setIsModalOpen(false)} onAddAlert={handleNewAlert} />}
      {viewingAlert && <AlertDetailsModal alert={viewingAlert} onClose={() => setViewingAlert(null)} />}
      {notification && 
        <Notification 
          message={notification.message} 
          type={notification.type} 
          onClose={() => setNotification(null)} 
        />
      }
    </div>
  );
}

export enum AlertSeverity {
    LOW = 'Low',
    MEDIUM = 'Medium',
    HIGH = 'High',
    CRITICAL = 'Critical',
}

export enum AlertStatus {
    ACTIVE = 'Active',
    MONITORING = 'Monitoring',
    RESOLVED = 'Resolved',
    UPDATING = 'Updating',
}

export interface Alert {
    id: string;
    title: string;
    type: string;
    description: string;
    location: string;
    affected: number;
    lat: number;
    lng: number;
    timestamp: Date;
    severity: AlertSeverity;
    status: AlertStatus;
}

export type Tab = 'Alerts' | 'Live Map' | 'Assessment' | 'AI Risk Prediction' | 'Emergency';

export type NotificationType = 'info' | 'success' | 'error';

import React from 'react';
import { TriangleAlert, MapPin, Eye, TrendingUp, Phone } from 'lucide-react';
import { Tab } from '../types';

interface NavTabsProps {
  activeTab: Tab;
  setActiveTab: (tab: Tab) => void;
}

const tabs: { name: Tab; icon: React.ReactNode }[] = [
  { name: 'Alerts', icon: <TriangleAlert className="h-4 w-4 mr-2" /> },
  { name: 'Live Map', icon: <MapPin className="h-4 w-4 mr-2" /> },
  { name: 'Assessment', icon: <Eye className="h-4 w-4 mr-2" /> },
  { name: 'AI Risk Prediction', icon: <TrendingUp className="h-4 w-4 mr-2" /> },
  { name: 'Emergency', icon: <Phone className="h-4 w-4 mr-2" /> },
];

const NavTabs: React.FC<NavTabsProps> = ({ activeTab, setActiveTab }) => {
  return (
    <div className="mt-8 bg-white rounded-lg shadow-sm p-2">
      <nav className="flex space-x-2">
        {tabs.map((tab) => (
          <button
            key={tab.name}
            onClick={() => setActiveTab(tab.name)}
            className={`flex-1 flex items-center justify-center py-2.5 px-4 rounded-md text-sm font-semibold transition-colors
              ${
                activeTab === tab.name
                  ? 'bg-gradient-to-r from-red-500 to-orange-500 text-white shadow'
                  : 'text-slate-600 hover:bg-slate-100'
              }`}
          >
            {tab.icon}
            {tab.name}
          </button>
        ))}
      </nav>
    </div>
  );
};

export default NavTabs;

import React, { useEffect, useRef } from 'react';
import { Alert, AlertSeverity, NotificationType } from '../types';
import { timeSince } from '../utils';

declare const L: any; // Use Leaflet from global scope

interface LiveMapProps {
  alerts: Alert[];
  setNotification: (message: string, type: NotificationType) => void;
}

const severityColors = {
    [AlertSeverity.CRITICAL]: '#ef4444', // red-500
    [AlertSeverity.HIGH]: '#f97316', // orange-500
    [AlertSeverity.MEDIUM]: '#eab308', // yellow-500
    [AlertSeverity.LOW]: '#3b82f6', // blue-500
};

const customIcon = (color: string) => L.divIcon({
    html: `<svg viewBox="0 0 24 24" width="32" height="32" fill="${color}" xmlns="http://www.w3.org/2000/svg"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/><circle cx="12" cy="9.5" r="2.5" fill="white"/></svg>`,
    className: '', // important to have empty className
    iconSize: [32, 32],
    iconAnchor: [16, 32],
    popupAnchor: [0, -32]
});


const LiveMap: React.FC<LiveMapProps> = ({ alerts, setNotification }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<any>(null);
    const markersRef = useRef<any[]>([]);

    useEffect(() => {
        if (mapContainerRef.current && !mapRef.current) {
            const map = L.map(mapContainerRef.current).setView([20.5937, 78.9629], 5);
            mapRef.current = map;

            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
            }).addTo(map);

            // Fix for map rendering half-loaded in a hidden tab
            setTimeout(() => {
                map.invalidateSize();
            }, 100);
        }
    }, []); 

    useEffect(() => {
        if (mapRef.current) {
            const map = mapRef.current;
            markersRef.current.forEach(marker => map.removeLayer(marker));
            markersRef.current = [];

            alerts.forEach(alert => {
                const color = severityColors[alert.severity] || 'gray';
                const buttonId = `respond-btn-${alert.id}`;
                const marker = L.marker([alert.lat, alert.lng], { icon: customIcon(color) }).addTo(map);
                marker.bindPopup(`
                    <div style="font-family: sans-serif; font-size: 14px; max-width: 250px; line-height: 1.5;">
                        <b style="font-size: 16px; color: #1e293b;">${alert.title}</b>
                        <p style="font-size: 13px; color: #475569; margin: 4px 0;">${alert.description}</p>
                        <hr style="border: 0; border-top: 1px solid #e2e8f0; margin: 8px 0;" />
                        <div style="display: grid; grid-template-columns: 80px 1fr; gap: 4px; color: #334155;">
                            <b>Severity:</b> <span>${alert.severity}</span>
                            <b>Location:</b> <span>${alert.location}</span>
                            <b>Affected:</b> <span>${alert.affected.toLocaleString()}</span>
                            <b>Time:</b> <span>${timeSince(alert.timestamp)}</span>
                        </div>
                        <button id="${buttonId}" style="width: 100%; margin-top: 12px; padding: 8px 12px; border: none; background: linear-gradient(to right, #f97316, #ef4444); color: white; border-radius: 6px; font-weight: 600; cursor: pointer;">Respond</button>
                    </div>
                `);

                marker.on('popupopen', () => {
                    const btn = document.getElementById(buttonId);
                    if (btn) {
                        btn.onclick = () => setNotification(`Response dispatched for: ${alert.title}`, 'success');
                    }
                });

                markersRef.current.push(marker);
            });
        }
    }, [alerts, setNotification]);

    return (
      <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
        <h2 className="text-xl font-bold mb-4">Live Disaster Map</h2>
        <p className="text-slate-600 mb-4">Showing real-time locations of active alerts.</p>
        <div ref={mapContainerRef} id="map" className="h-[500px] w-full rounded-md z-0" />
      </div>
    );
};

export default LiveMap;

