interface NewAlertModalProps {
  onClose: () => void;
  onAddAlert: (alert: Alert) => void;
}

const cityCoordinates: { [key: string]: { lat: number; lng: number } } = {
    'hyderabad': { lat: 17.3850, lng: 78.4867 },
    'pune': { lat: 18.5204, lng: 73.8567 },
    'bangalore': { lat: 12.9716, lng: 77.5946 },
    'chennai': { lat: 13.0827, lng: 80.2707 },
    'mumbai': { lat: 19.0760, lng: 72.8777 },
    'delhi': { lat: 28.7041, lng: 77.1025 },
};

const NewAlertModal: React.FC<NewAlertModalProps> = ({ onClose, onAddAlert }) => {
  const [report, setReport] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [assessedData, setAssessedData] = useState<{ title: string; summary: string, disasterType: string, severity: AlertSeverity } | null>(null);
  const [location, setLocation] = useState('');
  const [affected, setAffected] = useState(0);

  const handleAssessRisk = async () => {
    if (!report) return;
    setIsLoading(true);
    setError(null);
    setAssessedData(null);
    try {
      const result = await assessRiskAndCategorize(report);
      setAssessedData(result);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmitAlert = () => {
    if (!assessedData) {
        alert("Please assess the risk before creating an alert.");
        return;
    }
    if (!location) {
        alert("Please provide a location for the alert.");
        return;
    }

    const lowerCaseLocation = location.toLowerCase();
    const coords = cityCoordinates[lowerCaseLocation] || { lat: 20.5937, lng: 78.9629 }; // Default to center of India if city not found

    const newAlert: Alert = {
      id: `alert-${Date.now()}`,
      title: assessedData.title,
      type: assessedData.disasterType,
      description: assessedData.summary,
      location: location, 
      lat: coords.lat, 
      lng: coords.lng,
      affected: affected || 0,
      timestamp: new Date(),
      severity: assessedData.severity,
      status: AlertStatus.ACTIVE,
    };
    onAddAlert(newAlert);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-lg flex flex-col">
        <div className="p-5 border-b flex justify-between items-center">
          <h2 className="text-xl font-semibold text-slate-800">Create New Emergency Alert</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600"><X size={24} /></button>
