          </div>

          <button
            onClick={handleAssessRisk}
            disabled={!report || isLoading}
            className="w-full flex justify-center items-center gap-2 bg-slate-500 text-white rounded-lg px-4 py-2.5 font-medium hover:bg-slate-600 disabled:bg-slate-400 disabled:cursor-not-allowed transition-colors"
          >
            <Bot className="h-5 w-5" />
            {isLoading ? 'Assessing...' : 'Use AI to Assess Risk & Categorize'}
          </button>

          {error && <div className="text-red-600 text-center text-sm">{error}</div>}

          {assessedData && (
            <div className="bg-slate-50 p-4 rounded-md border text-sm space-y-4">
