                <p><strong className="text-slate-500">Title:</strong> {assessedData.title}</p>
                <p><strong className="text-slate-500">Type:</strong> {assessedData.disasterType}</p>
                <p><strong className="text-slate-500">Severity:</strong> <span className="font-bold text-red-600">{assessedData.severity}</span></p>
              </div>
              <div className="space-y-3 pt-3 border-t">
                  <div>
                      <label htmlFor="location" className="block text-sm font-medium text-slate-700">Location (City Name)</label>
                      <input
                          type="text"
                          id="location"
                          value={location}
                          onChange={(e) => setLocation(e.target.value)}
