                          className="mt-1 block w-full bg-white border border-slate-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-orange-500 focus:border-orange-500 sm:text-sm"
                      />
                  </div>
                  <div>
                      <label htmlFor="affected" className="block text-sm font-medium text-slate-700">Number of People Affected</label>
                      <input
                          type="number"
                          id="affected"
                          value={affected === 0 ? '' : affected}
