export const getChatbotResponse = async (message: string, history: { role: string, parts: { text: string }[] }[]) => {
    try {
        const chat = ai.chats.create({
            model: 'gemini-3-flash-preview',
            history: history,
            config: {
                systemInstruction: "You are a knowledgeable and empathetic Health & Disaster Expert. Your role is to provide clear, concise, and actionable advice on emergency situations, first aid, and crisis management. Combine expertise in both healthcare and disaster response. Be a calm and reassuring guide."
