import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import StatCards from './components/StatCards';
import NavTabs from './components/NavTabs';
import AlertsSection from './components/AlertsSection';
import NewAlertModal from './components/NewAlertModal';
import EditAlertModal from './components/EditAlertModal';
import LiveMap from './components/LiveMap';
import ProximityAnalysisSection from './components/ProximityAnalysisSection';
import AssessmentSection from './components/AssessmentSection';
import AlertDetailsModal from './components/AlertDetailsModal';
import Notification from './components/Notification';
import Chatbot from './components/Chatbot';
import { statCardData } from './constants';
import { Alert, Tab, AlertStatus, NotificationType, AlertSeverity } from './types';
import { getAlerts, createAlert as apiCreateAlert, updateAlert as apiUpdateAlert } from './services/apiService';
import { getChatbotResponse } from './services/geminiService';

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>('Alerts');
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingAlert, setEditingAlert] = useState<Alert | null>(null);
  const [viewingAlert, setViewingAlert] = useState<Alert | null>(null);
  const [notification, setNotification] = useState<{ message: string; type: NotificationType } | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isChatbotOpen, setIsChatbotOpen] = useState(false);
  const [chatHistory, setChatHistory] = useState<{ role: string, parts: { text: string }[] }[]>([
    {
      role: 'model',
      parts: [{ text: "Hello! I'm your Health & Disaster Expert. How can I assist you with crisis management, first aid, or emergency planning today?" }],
    },
  ]);

  // State for filters
  const [searchQuery, setSearchQuery] = useState('');
  const [severityFilter, setSeverityFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');

  useEffect(() => {
    const fetchAlerts = async () => {
      try {
        const fetchedAlerts = await getAlerts();
        setAlerts(fetchedAlerts);
      } catch (error) {
        showNotification('Failed to load alerts. Please try again later.', 'error');
        console.error(error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchAlerts();
  }, []);

  const handleNewAlert = async (alertData: Omit<Alert, 'id' | 'timestamp'>) => {
    try {
      const newAlert = await apiCreateAlert(alertData);
      setAlerts(prevAlerts => [newAlert, ...prevAlerts]);
      showNotification(`New alert "${newAlert.title}" has been successfully created.`, 'success');
    } catch (error) {
      showNotification('Failed to create alert. Please try again.', 'error');
      console.error(error);
    }
  };

  const handleUpdateAlert = async (updatedAlert: Alert) => {
    try {
        const savedAlert = await apiUpdateAlert(updatedAlert);
        setAlerts(prevAlerts => prevAlerts.map(alert => alert.id === savedAlert.id ? savedAlert : alert));
        showNotification(`Alert "${savedAlert.title}" has been successfully updated.`, 'success');
    } catch (error) {
        showNotification('Failed to update alert. Please try again.', 'error');
        console.error(error);
    }
  };

  const showNotification = (message: string, type: NotificationType = 'info') => {
    setNotification({ message, type });
  };

  const handleSendMessage = async (message: string) => {
    const userMessage = { role: 'user', parts: [{ text: message }] };
    setChatHistory(prev => [...prev, userMessage]);

    try {
      const response = await getChatbotResponse(message, chatHistory);
      const modelMessage = { role: 'model', parts: [{ text: response }] };
      setChatHistory(prev => [...prev, modelMessage]);
    } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'An unexpected error occurred.';
        const modelErrorMessage = { role: 'model', parts: [{ text: `Error: ${errorMessage}` }] };
        setChatHistory(prev => [...prev, modelErrorMessage]);
        showNotification(errorMessage, 'error');
    }
  };

  const activeAlerts = alerts.filter(alert => alert.status === AlertStatus.ACTIVE);

  const filteredAlerts = useMemo(() => {
    return alerts.filter(alert => {
        const searchLower = searchQuery.toLowerCase();
        const matchesSearch = (
            alert.title.toLowerCase().includes(searchLower) ||
            alert.description.toLowerCase().includes(searchLower) ||
            alert.type.toLowerCase().includes(searchLower) ||
            alert.location.toLowerCase().includes(searchLower)
        );
        const matchesSeverity = severityFilter === 'All' || alert.severity === severityFilter;
        const matchesStatus = statusFilter === 'All' || alert.status === statusFilter;

        return matchesSearch && matchesSeverity && matchesStatus;
    });
  }, [alerts, searchQuery, severityFilter, statusFilter]);

  return (
    <div className="bg-slate-50 min-h-screen font-sans text-slate-800">
      <Header setNotification={showNotification} />
      <main className="p-4 sm:p-6 lg:p-8">
        <StatCards stats={statCardData} />
        <NavTabs activeTab={activeTab} setActiveTab={setActiveTab} />

        {isLoading ? (
          <div className="mt-6 text-center">Loading alerts...</div>
        ) : (
          <>
            {activeTab === 'Alerts' && (
              <AlertsSection 
                alerts={filteredAlerts} 
                onNewAlertClick={() => setIsModalOpen(true)}
                onViewDetails={setViewingAlert}
                onEditAlert={setEditingAlert}
                setNotification={showNotification}
                searchQuery={searchQuery}
                setSearchQuery={setSearchQuery}
                severityFilter={severityFilter}
                setSeverityFilter={setSeverityFilter}
                statusFilter={statusFilter}
                setStatusFilter={setStatusFilter}
              />
            )}
            {activeTab === 'Live Map' && (
              <LiveMap alerts={activeAlerts} setNotification={showNotification} />
            )}
            {activeTab === 'Proximity Analysis' && (
              <ProximityAnalysisSection alerts={activeAlerts} setNotification={showNotification} />
            )}
            {activeTab === 'Assessment' && (
              <AssessmentSection alerts={alerts} setNotification={showNotification} />
            )}
            {activeTab === 'AI Risk Prediction' && (
                <div className="mt-6 bg-white p-6 rounded-lg shadow-sm">
                    <h2 className="text-xl font-bold mb-4">{activeTab}</h2>
                    <p className="text-slate-600">This is a placeholder for the {activeTab} section. Functionality would be built out here.</p>
                </div>
            )}
          </>
        )}
      </main>
      {isModalOpen && <NewAlertModal onClose={() => setIsModalOpen(false)} onAddAlert={handleNewAlert} />}
      {editingAlert && <EditAlertModal alert={editingAlert} onClose={() => setEditingAlert(null)} onUpdateAlert={handleUpdateAlert} />}
      {viewingAlert && <AlertDetailsModal alert={viewingAlert} onClose={() => setViewingAlert(null)} />}
      {notification && 
        <Notification 
          message={notification.message} 
          type={notification.type} 
          onClose={() => setNotification(null)} 
        />
      }
      <Chatbot
        isOpen={isChatbotOpen}
        onToggle={() => setIsChatbotOpen(!isChatbotOpen)}
        messages={chatHistory}
        onSendMessage={handleSendMessage}
      />
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Bot, Send, CornerDownLeft } from 'lucide-react';

interface ChatbotProps {
    isOpen: boolean;
    onToggle: () => void;
    messages: { role: string; parts: { text: string }[] }[];
    onSendMessage: (message: string) => void;
}

const Chatbot: React.FC<ChatbotProps> = ({ isOpen, onToggle, messages, onSendMessage }) => {
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(scrollToBottom, [messages]);

    useEffect(() => {
        if (messages.length > 0 && messages[messages.length - 1].role === 'user') {
            setIsTyping(true);
        } else {
            setIsTyping(false);
        }
    }, [messages]);

    const handleSend = () => {
        if (input.trim()) {
            onSendMessage(input);
            setInput('');
        }
    };

    const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            handleSend();
        }
    };

    return (
        <>
            <button
                onClick={onToggle}
                className="fixed bottom-6 right-6 bg-gradient-to-r from-purple-600 to-indigo-600 text-white rounded-full p-4 shadow-lg hover:scale-110 transition-transform z-40"
                aria-label="Toggle Chatbot"
            >
                {isOpen ? <X size={24} /> : <MessageCircle size={24} />}
            </button>

            <div
                className={`fixed bottom-24 right-6 w-[380px] h-[550px] bg-white border border-slate-300 rounded-xl shadow-2xl flex flex-col transition-all duration-300 ease-in-out z-50 ${
                    isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'
                }`}
            >
                <div className="p-4 border-b bg-slate-50 rounded-t-xl flex items-center gap-3">
                    <Bot className="h-7 w-7 text-indigo-600" />
                    <div>
                        <h3 className="font-bold text-lg text-slate-800">Health & Disaster Expert</h3>
                        <p className="text-xs text-slate-500">Powered by Gemini</p>
                    </div>
                </div>

                <div className="flex-1 p-4 overflow-y-auto bg-slate-100">
                    <div className="space-y-4">
                        {messages.map((msg, index) => (
                            <div key={index} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[80%] p-3 rounded-lg ${msg.role === 'user' ? 'bg-indigo-500 text-white' : 'bg-white text-slate-700 border'}`}>
                                    <p className="text-sm">{msg.parts[0].text}</p>
                                </div>
                            </div>
                        ))}
                        {isTyping && (
                            <div className="flex justify-start">
                                <div className="max-w-[80%] p-3 rounded-lg bg-white text-slate-700 border">
                                    <div className="flex items-center space-x-1">
                                        <span className="h-2 w-2 bg-slate-300 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                        <span className="h-2 w-2 bg-slate-300 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                        <span className="h-2 w-2 bg-slate-300 rounded-full animate-bounce"></span>
                                    </div>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>
                </div>

                <div className="p-4 border-t bg-white rounded-b-xl">
                    <div className="relative">
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyPress={handleKeyPress}
                            placeholder="Ask a question..."
                            className="w-full bg-slate-100 border-slate-300 rounded-lg py-2 pl-4 pr-12 focus:ring-indigo-500 focus:border-indigo-500"
                        />
                        <button onClick={handleSend} className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-indigo-500 text-white rounded-md hover:bg-indigo-600">
                            <Send size={18} />
                        </button>
                    </div>
                     <p className="text-xs text-slate-400 mt-2 text-center">Press <CornerDownLeft size={12} className="inline-block" /> to send.</p>
                </div>
            </div>
        </>
    );
};

export default Chatbot;

import { GoogleGenAI, Type } from "@google/genai";
import { Alert, AlertSeverity } from "../types";
import { nearbyServices } from '../constants';

// FIX: Initialize GoogleGenAI with process.env.API_KEY as per the coding guidelines.
// The API key is expected to be available in the execution environment.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const assessRiskAndCategorize = async (report: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze the following disaster report and provide a structured JSON response.
        Report: "${report}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "A concise title for the alert (e.g., 'Structural Collapse Downtown')." },
            summary: { type: Type.STRING, description: "A brief, one-sentence summary of the event." },
            disasterType: { type: Type.STRING, description: "Categorize the disaster type (e.g., 'Earthquake', 'Flood', 'Fire', 'Industrial Accident')." },
            severity: {
              type: Type.STRING,
              description: "Assess the severity. Must be one of: 'Low', 'Medium', 'High', 'Critical'.",
            },
          },
          required: ["title", "summary", "disasterType", "severity"],
        },
      },
    });

    const parsed = JSON.parse(response.text);
    // Ensure severity aligns with our enum
    const severityValues = Object.values(AlertSeverity) as string[];
    if (!severityValues.includes(parsed.severity)) {
        throw new Error(`Invalid severity returned: ${parsed.severity}`);
    }

    return parsed as { title: string; summary: string, disasterType: string, severity: AlertSeverity };
  } catch (error) {
    console.error("Error assessing risk:", error);
    throw new Error("Failed to analyze the disaster report with AI.");
  }
};

export const generateActionPlan = async (disasterType: string, severity: AlertSeverity) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a concise, step-by-step emergency action plan for a '${disasterType}' of '${severity}' severity. The plan should be a list of 3-5 key actions for first responders. **Strictly use plain text only.** Format it as simple numbered lines (e.g., "1. Do this." then "2. Do that.") without any Markdown or special symbols.`,
    });
    return response.text;
  } catch (error) {
    console.error("Error generating action plan:", error);
    throw new Error("Failed to generate an action plan.");
  }
};

export const translateAlert = async (text: string, languages: string[]) => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Translate the following alert into these languages: ${languages.join(', ')}. Return a JSON object where keys are the language names and values are the translations.
            Alert: "${text}"`,
            config: {
                responseMimeType: "application/json",
            },
        });
        return JSON.parse(response.text) as Record<string, string>;
    } catch (error)
        console.error("Error translating alert:", error);
        throw new Error("Failed to translate the alert.");
    }
};

export const generateDetailedAssessment = async (alert: Alert) => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Provide a detailed risk assessment for the following emergency alert. 
            **IMPORTANT: The entire response must be in plain text.** Do not use any special formatting symbols like Markdown (no '###', '**', or '*'). Use clear headings and standard paragraph breaks. The tone should be professional and clear.

            Alert Details:
            - Title: ${alert.title}
            - Type: ${alert.type}
            - Location: ${alert.location}
            - Severity: ${alert.severity}
            - Description: ${alert.description}
            - People Affected: ${alert.affected.toLocaleString()}

            The assessment should include the following sections:
            1.  Risk Analysis: A detailed analysis of the current situation and potential escalations.
            2.  Potential Impact: Assess the potential impact on population, infrastructure, and environment.
            3.  Recommended Actions: Provide a list of immediate, actionable recommendations for response teams.
            `,
        });
        return response.text;
    } catch (error) {
        console.error("Error generating detailed assessment:", error);
        throw new Error("Failed to generate a detailed assessment.");
    }
};

